// Hero (focused) card
// ---------------------------------------------------------------------------

interface FocusedCalendarCardProps {
  calendar: Calendar;
  isActive: boolean;
  onClick: () => void;
  onEdit?: () => void;
  onDuplicate?: () => void;
  onLink?: () => void;
  onDelete?: () => void;
  onUpdateCalendarProperty?: CalendarsListContentProps['onUpdateCalendarProperty'];
}

const FocusedCalendarCard: React.FC<FocusedCalendarCardProps> = ({
  calendar,
  isActive,
  onClick,
  onEdit,
  onDuplicate,
  onLink,
  onDelete,
  onUpdateCalendarProperty,
}) => {
  const theme = useTheme();
  const [menuAnchor, setMenuAnchor] = useState<HTMLElement | null>(null);

  const pnl = calendar.total_pnl || 0;
  const trades = calendar.total_trades || 0;
  const empty = trades === 0;
  const positive = pnl >= 0;
  const initial = calendar.account_balance || 0;
  const current = initial + pnl;
  const pct = empty || initial === 0 ? 0 : (pnl / initial) * 100;

  const pnlColor = empty
    ? theme.palette.text.secondary
    : positive
      ? theme.palette.success.main
      : theme.palette.error.main;

  const curve = useMemo(() => buildEquityCurve(calendar), [calendar]);
  const surface = alpha(theme.palette.common.white, 0.03);
  const divider = alpha(theme.palette.common.white, 0.08);
  const isLight = theme.palette.mode === 'light';

  return (
    <Box
      onClick={onClick}
      sx={{
        p: 1.75,
        borderRadius: '12px',
        cursor: 'pointer',
        position: 'relative',
        bgcolor: isLight ? alpha(theme.palette.background.paper, 0.7) : surface,
        border: `1px solid ${
          isActive
            ? alpha(theme.palette.primary.main, 0.45)
            : isLight
              ? theme.palette.divider
              : divider
        }`,
        boxShadow: isActive
          ? `0 0 0 1px ${alpha(theme.palette.primary.main, 0.25)} inset, 0 8px 20px ${alpha(theme.palette.primary.main, 0.08)}`
          : 'none',
        transition: 'border-color .15s, box-shadow .15s',
      }}
    >
      {/* Header row */}
      <Stack
        direction="row"
        alignItems="center"
        spacing={1.25}
        sx={{ mb: 1.5 }}
      >
        <HeroSwatch calendar={calendar} size={28} radius={7} />
        <Box sx={{ flex: 1, minWidth: 0 }}>
          <Typography
            sx={{
              fontWeight: 600,
              fontSize: '0.8125rem',
              lineHeight: 1.2,
              whiteSpace: 'nowrap',
              overflow: 'hidden',
              textOverflow: 'ellipsis',
            }}
          >
            {calendar.name}
          </Typography>
          <Typography
            sx={{
              fontSize: '0.6875rem',
              color: 'text.secondary',
              mt: '2px',
            }}
          >
            <Box component="span" sx={monoSx}>
              {trades}
            </Box>{' '}
            trades · {empty ? 'no activity' : 'active'}
          </Typography>
        </Box>
        {onUpdateCalendarProperty && (
          <ShareButton
            type="calendar"
            item={calendar}
            onUpdateItemProperty={onUpdateCalendarProperty}
            size="small"
          />
        )}
        <IconButton
          size="small"
          onClick={(e) => {
            e.stopPropagation();
            setMenuAnchor(e.currentTarget);
          }}
          sx={{ color: 'text.secondary', p: 0.5 }}
        >
          <MoreVertIcon sx={{ fontSize: 18 }} />
        </IconButton>
        <Menu
          anchorEl={menuAnchor}
          open={Boolean(menuAnchor)}
          onClose={() => setMenuAnchor(null)}
          onClick={(e) => e.stopPropagation()}
          transformOrigin={{ horizontal: 'right', vertical: 'top' }}
          anchorOrigin={{ horizontal: 'right', vertical: 'bottom' }}
        >
          <MenuItem
            onClick={() => {
              setMenuAnchor(null);
              onEdit?.();
            }}
          >
            <ListItemIcon>
              <EditIcon fontSize="small" />
            </ListItemIcon>
            <ListItemText>Edit</ListItemText>
          </MenuItem>
          <MenuItem
            onClick={() => {
              setMenuAnchor(null);
              onDuplicate?.();
            }}
          >
            <ListItemIcon>
              <DuplicateIcon fontSize="small" />
            </ListItemIcon>
            <ListItemText>Duplicate</ListItemText>
          </MenuItem>
          <MenuItem
            onClick={() => {
              setMenuAnchor(null);
              onLink?.();
            }}
          >
            <ListItemIcon>
              <LinkIcon fontSize="small" />
            </ListItemIcon>
            <ListItemText>Link Calendar</ListItemText>
          </MenuItem>
          <MenuItem
            onClick={() => {
              setMenuAnchor(null);
              onDelete?.();
            }}
            sx={{ color: 'error.main' }}
          >
            <ListItemIcon>
              <DeleteIcon fontSize="small" sx={{ color: 'error.main' }} />
            </ListItemIcon>
            <ListItemText>Delete</ListItemText>
          </MenuItem>
        </Menu>
      </Stack>

      {/* PnL row */}
      <Stack
        direction="row"
        alignItems="baseline"
        spacing={1}
        sx={{ mb: 1.25 }}
      >
        <Typography
          sx={{
            ...monoSx,
            fontSize: '1.5rem',
            color: pnlColor,
            lineHeight: 1,
            letterSpacing: '-0.015em',
          }}
        >
          {positive && !empty ? '+' : ''}
          {fmtCurrencyExact(pnl)}
        </Typography>
        <Typography
          sx={{
            ...monoSx,
            fontSize: '0.75rem',
            color: pnlColor,
          }}
        >
          {empty
            ? '0.00%'
            : `${positive ? '+' : ''}${pct.toFixed(2)}%`}
        </Typography>
      </Stack>

      {/* Sparkline */}
      {empty || !curve ? (
        <Box
          sx={{
            height: 72,
            display: 'grid',
            placeItems: 'center',
            color: 'text.secondary',
            fontSize: '0.6875rem',
          }}
        >
          {empty ? 'No trades yet' : 'Not enough data for a curve'}
        </Box>
      ) : (
        <ResponsiveSparkline
          data={curve}
          color={pnlColor}
          height={72}
          strokeWidth={1.6}
        />
      )}

      {/* Inline 3-stat row */}
      <Stack
        direction="row"
        spacing={1.5}
        sx={{
          mt: 1.25,
          pt: 1.25,
          borderTop: `1px solid ${divider}`,
        }}
      >
        <InlineStat
          label="Win"
          value={empty ? '—' : `${(calendar.win_rate || 0).toFixed(0)}%`}
        />
        <Box sx={{ width: '1px', bgcolor: divider }} />
        <InlineStat
          label="PF"
          value={empty ? '—' : (calendar.profit_factor || 0).toFixed(2)}
          tooltip="Profit factor: gross profit / gross loss"
        />
        <Box sx={{ width: '1px', bgcolor: divider }} />
        <InlineStat
          label="DD"
          value={empty ? '—' : `${(calendar.max_drawdown || 0).toFixed(1)}%`}
          tooltip="Max drawdown"
        />
        <Box sx={{ width: '1px', bgcolor: divider }} />
        <InlineStat label="Bal" value={fmtCurrencyCompact(current)} />
      </Stack>
    </Box>
  );
};

interface InlineStatProps {
  label: string;
  value: string;
  tooltip?: string;
}

const InlineStat: React.FC<InlineStatProps> = ({ label, value, tooltip }) => {
  const inner = (
    <Box sx={{ flex: 1, minWidth: 0 }}>
      <Typography
        sx={{
          fontSize: '0.625rem',
          color: 'text.secondary',
          textTransform: 'uppercase',
          letterSpacing: '0.06em',
          fontWeight: 600,
          mb: '2px',
          lineHeight: 1,
        }}
      >
        {label}
      </Typography>
      <Typography
        sx={{
          ...monoSx,
          fontSize: '0.75rem',
          lineHeight: 1,
          whiteSpace: 'nowrap',
          overflow: 'hidden',
          textOverflow: 'ellipsis',
        }}
      >
        {value}
      </Typography>
    </Box>
  );
  return tooltip ? (
    <Tooltip title={tooltip} arrow placement="top">
      {inner}
    </Tooltip>
  ) : (
    inner
  );
};

